/**
 * Get CSS variable reference for a token path
 * Usage: getToken("color.primary.500") → var(--token-color-primary-500)
 */
export function getToken(path: TokenPath): string {
  const varName = path.replace(/\./g, "-").replace(/([A-Z])/g, "-$1").toLowerCase();
  return `var(--token-${varName})`;
}
